(function () {
    'use strict';

    const form = document.getElementById('chat-form');
    const input = document.getElementById('message-input');
    const messagesDiv = document.getElementById('messages');
    const sendBtn = document.getElementById('send-btn');

    if (!form || !input || !messagesDiv || !sendBtn) return;

    const socket = new WebSocket(
        (window.location.protocol === 'https:' ? 'wss://' : 'ws://') +
        window.location.host +
        '/ws/chat/'
    );

    function appendMessage(text, sender) {
        const msg = document.createElement('div');
        msg.className = 'flex ' + (sender === 'user' ? 'justify-end' : 'justify-start');
        const bubble = document.createElement('div');
        bubble.className =
            'max-w-[80%] rounded-lg px-4 py-2 ' +
            (sender === 'user'
                ? 'bg-blue-600 text-white rounded-br-none'
                : 'bg-gray-200 text-gray-900 rounded-bl-none whitespace-pre-wrap');
        bubble.textContent = text;
        msg.appendChild(bubble);
        messagesDiv.appendChild(msg);
        messagesDiv.scrollTop = messagesDiv.scrollHeight;
    }

    function appendAssistantPlaceholder() {
        const msg = document.createElement('div');
        msg.id = 'assistant-msg';
        msg.className = 'flex justify-start';
        const bubble = document.createElement('div');
        bubble.className = 'max-w-[80%] rounded-lg px-4 py-2 bg-gray-200 text-gray-900 rounded-bl-none whitespace-pre-wrap';
        bubble.textContent = '';
        msg.appendChild(bubble);
        messagesDiv.appendChild(msg);
        messagesDiv.scrollTop = messagesDiv.scrollHeight;
        return bubble;
    }

    function updateAssistantText(bubble, token) {
        bubble.textContent += token;
        messagesDiv.scrollTop = messagesDiv.scrollHeight;
    }

    let assistantBubble = null;
    let fullResponse = '';

    socket.onopen = function () {
        console.log('WebSocket connected');
    };

    socket.onclose = function () {
        console.log('WebSocket disconnected');
    };

    socket.onerror = function (error) {
        console.error('WebSocket error:', error);
        appendMessage('Connection error. Please refresh the page.', 'assistant');
    };

    socket.onmessage = function (event) {
        let data;
        try {
            data = JSON.parse(event.data);
        } catch {
            return;
        }

        if (data.type === 'token' && assistantBubble) {
            updateAssistantText(assistantBubble, data.token);
            fullResponse += data.token;
        }

        if (data.type === 'complete') {
            input.disabled = false;
            sendBtn.disabled = false;
            input.focus();
            if (assistantBubble) {
                assistantBubble.textContent = data.content;
                assistantBubble = null;
            }
        }

        if (data.type === 'error') {
            input.disabled = false;
            sendBtn.disabled = false;
            if (assistantBubble) {
                assistantBubble.textContent = 'Error: ' + data.message;
                assistantBubble = null;
            } else {
                appendMessage('Error: ' + data.message, 'assistant');
            }
        }
    };

    form.addEventListener('submit', function (event) {
        event.preventDefault();
        const message = input.value.trim();
        if (!message || socket.readyState !== WebSocket.OPEN) return;

        appendMessage(message, 'user');
        input.value = '';
        input.disabled = true;
        sendBtn.disabled = true;
        assistantBubble = appendAssistantPlaceholder();
        fullResponse = '';

        socket.send(JSON.stringify({ message: message }));
    });
})();

